package ers

import (
	"crypto/ecdsa"
	"crypto/rsa"
	"crypto/x509"
	"encoding/hex"
	"fmt"
	"testing"

	"github.com/palisadeinc/mpc-recovery/math"
)

type derivation struct {
	chainPath           []uint32
	derivedPubKeyHex    string
	derivedChainCodeHex string
}

type deriveTestCase struct {
	name                string
	curveName           string
	ersPrivateKeyHex    string
	ersLabel            []byte
	recoveryData        string
	expectedDerivations []derivation
}

func TestCanRecoverDerivedKeyFromRecoveryData(t *testing.T) {

	for _, tc := range deriveTestCases {
		t.Run(fmt.Sprintf(tc.name), func(t *testing.T) {

			// Recover master key and master chain code

			ersPrivateKeyBytes, err := hex.DecodeString(tc.ersPrivateKeyHex)
			requireNoError(t, err)
			ersPKCS8PrivateKey, err := x509.ParsePKCS8PrivateKey(ersPrivateKeyBytes)
			requireNoError(t, err)
			ersRSAPrivateKey, isRSAPrivateKey := ersPKCS8PrivateKey.(*rsa.PrivateKey)
			requireTrue(t, isRSAPrivateKey)
			rsaDecryptor := NewRSADecryptor(ersRSAPrivateKey)

			ellipticCurve, masterPrivateKeyBytes, masterChainCode, err := RecoverPrivateKey(rsaDecryptor, tc.ersLabel, []byte(tc.recoveryData), nil)
			requireNoError(t, err)
			requireTrue(t, ellipticCurve == tc.curveName)

			// Check that we can use the recovered master key and master chain code to get same derived keys and chain codes as the TSM

			curve, err := math.NewCurve(tc.curveName)
			requireNoError(t, err)

			masterPrivateKey := curve.NewScalarBytes(masterPrivateKeyBytes)
			masterPublicKey := curve.G().Mul(masterPrivateKey)

			for _, e := range tc.expectedDerivations {

				var actualDerivedPub math.Point
				var actualDerivedChainCode []byte

				var err error

				switch tc.curveName {
				case "secp256k1":
					actualDerivedPub, _, actualDerivedChainCode, err = DeriveSecp256k1(masterPublicKey, masterPrivateKey, masterChainCode, e.chainPath)

					// Public key is DER encoded in ECDSA, so we first convert to math.Point
					derPubKeyBytes, err := hex.DecodeString(e.derivedPubKeyHex)
					requireNoError(t, err)
					expectedDerivedPublicKeyGeneric, err := ParsePublicKey(derPubKeyBytes)
					expectedDerivedPublicKey := expectedDerivedPublicKeyGeneric.(*ecdsa.PublicKey)
					requireNoError(t, err)
					expectedDerivedPub, err := curve.NewPoint(expectedDerivedPublicKey.X, expectedDerivedPublicKey.Y)
					requireNoError(t, err)
					requireTrue(t, expectedDerivedPub.Equals(actualDerivedPub))

					requireTrue(t, e.derivedChainCodeHex == hex.EncodeToString(actualDerivedChainCode))

				case "ED-25519":
					actualDerivedPub, _, actualDerivedChainCode, err = DeriveEd25519(masterPublicKey, masterPrivateKey, masterChainCode, e.chainPath)

					requireTrue(t, e.derivedPubKeyHex == hex.EncodeToString(actualDerivedPub.Encode()))
					requireTrue(t, e.derivedChainCodeHex == hex.EncodeToString(actualDerivedChainCode))

				default:
					panic("curve does not support derivation")
				}
				requireNoError(t, err)

			}
		})
	}

}

